const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const cache = {};

app.post('/api/verify-nin', async (req, res) => {
  const { nin } = req.body;

  if (!nin) {
    return res.status(400).json({ error: 'NIN is required' });
  }

  if (cache[nin]) {
    return res.json(cache[nin]);
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/nin',
      { number: nin },
      {
        headers: {
          'app-id': process.env.PREMBLY_APP_ID,
          'x-api-key': process.env.PREMBLY_API_KEY,
        },
      }
    );

    const data = response.data;
    cache[nin] = data;
    return res.json(data);
  } catch (error) {
    if (error.response) {
      return res.status(error.response.status).json(error.response.data);
    }
    return res.status(500).json({ error: 'Internal server error' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server listening on port ${PORT}`);
});

